import { useEffect, useState, type CSSProperties } from "react";

import { AutomatonDrawer } from "./components/drawer/AutomatonDrawer";
import { AutomatonCanvas } from "./components/grid/AutomatonCanvas";
import {
  mockAutomatons,
  SIMULATED_VIEWER_ADDRESS
} from "./lib/mock-automatons";
import { themeTokens } from "./theme/tokens";

const navigationItems = ["Spawn", "Strategies", "Skills"] as const;

const systemNotes = [
  "Canvas interactions are local-only in this milestone, but they already honor hover, click, and owned-label rules.",
  "The drawer shell is driven by shared automaton detail types so later data wiring can replace mock payloads without redesigning the contract.",
  "Steward-only command execution is previewed with a simulated connected wallet and read-only fallback copy."
] as const;

type ThemeStyle = CSSProperties & Record<`--${string}`, string>;

function truncateAddress(value: string): string {
  return `${value.slice(0, 6)}...${value.slice(-4)}`;
}

function isOwnedByViewer(canisterId: string): boolean {
  const automaton = mockAutomatons.find((entry) => entry.canisterId === canisterId);

  if (automaton === undefined) {
    return false;
  }

  return (
    automaton.steward.address.toLowerCase() ===
    SIMULATED_VIEWER_ADDRESS.toLowerCase()
  );
}

export default function App() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scope, setScope] = useState<"all" | "mine">("all");
  const [selectedCanisterId, setSelectedCanisterId] = useState<string | null>(
    null
  );

  const visibleAutomatons =
    scope === "mine"
      ? mockAutomatons.filter(
          (entry) =>
            entry.steward.address.toLowerCase() ===
            SIMULATED_VIEWER_ADDRESS.toLowerCase()
        )
      : mockAutomatons;

  const selectedAutomaton =
    visibleAutomatons.find((entry) => entry.canisterId === selectedCanisterId) ??
    null;

  useEffect(() => {
    if (
      selectedCanisterId !== null &&
      !visibleAutomatons.some((entry) => entry.canisterId === selectedCanisterId)
    ) {
      setSelectedCanisterId(null);
    }
  }, [selectedCanisterId, visibleAutomatons]);

  useEffect(() => {
    if (selectedCanisterId === null) {
      return;
    }

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setSelectedCanisterId(null);
      }
    };

    window.addEventListener("keydown", handleKeyDown);

    return () => {
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [selectedCanisterId]);

  const themeStyle: ThemeStyle = {
    "--color-bg": themeTokens.colors.background,
    "--color-panel": themeTokens.colors.panel,
    "--color-panel-strong": themeTokens.colors.panelStrong,
    "--color-ink": themeTokens.colors.ink,
    "--color-line": themeTokens.colors.line,
    "--color-accent": themeTokens.colors.accent,
    "--color-accent-soft": themeTokens.colors.accentSoft,
    "--color-muted": themeTokens.colors.muted,
    "--color-muted-strong": themeTokens.colors.mutedStrong,
    "--color-inverse": themeTokens.colors.inverse,
    "--color-drawer-bg": themeTokens.colors.drawerBackground,
    "--color-drawer-text": themeTokens.colors.drawerText,
    "--color-drawer-muted": themeTokens.colors.drawerMuted,
    "--color-drawer-subtle": themeTokens.colors.drawerSubtle,
    "--color-tier-normal": themeTokens.colors.tierNormal,
    "--color-tier-low": themeTokens.colors.tierLow,
    "--color-tier-critical": themeTokens.colors.tierCritical,
    "--font-display": themeTokens.typography.display,
    "--font-body": themeTokens.typography.body,
    "--space-2xs": themeTokens.spacing["2xs"],
    "--space-xs": themeTokens.spacing.xs,
    "--space-sm": themeTokens.spacing.sm,
    "--space-md": themeTokens.spacing.md,
    "--space-lg": themeTokens.spacing.lg,
    "--space-xl": themeTokens.spacing.xl,
    "--space-2xl": themeTokens.spacing["2xl"],
    "--border-strong": themeTokens.borderWidths.strong,
    "--border-hairline": themeTokens.borderWidths.hairline,
    "--duration-fast": themeTokens.motion.fast,
    "--duration-base": themeTokens.motion.base
  };

  return (
    <div className="app-shell" style={themeStyle}>
      <header className="site-header">
        <div className="brand-lockup">
          <p className="brand-tagline">Self-sovereign AI agents on-chain</p>
          <h1 className="brand-wordmark">ic-automaton</h1>
        </div>

        <button
          aria-controls="primary-navigation"
          aria-expanded={menuOpen}
          className="menu-toggle"
          onClick={() => {
            setMenuOpen((open) => !open);
          }}
          type="button"
        >
          MENU
        </button>

        <div
          className={`header-actions${menuOpen ? " is-open" : ""}`}
          id="primary-navigation"
        >
          <nav aria-label="Primary" className="nav-cluster">
            {navigationItems.map((item) => (
              <button className="nav-button" key={item} type="button">
                {item}
              </button>
            ))}
          </nav>

          <div className="header-utility">
            <span className="live-pill">{mockAutomatons.length} LIVE</span>
            <button className="wallet-button is-connected" type="button">
              {truncateAddress(SIMULATED_VIEWER_ADDRESS)}
            </button>
          </div>
        </div>
      </header>

      <main className="shell-main">
        <section className="frame frame-stage">
          <div className="stage-toolbar">
            <div className="stage-copy">
              <p className="section-label">Grid view</p>
              <h2>
                Living automatons rendered on canvas, with click-through drawer
                inspection and steward shell previews.
              </h2>
              <p className="hero-body">
                M04 replaces the static viewport placeholder with a local
                canvas-based organism map. Hover reveals tier and net worth,
                owned automatons keep their labels visible, and click opens the
                bottom drawer shell without depending on the indexer yet.
              </p>
            </div>

            <div className="stage-meta">
              <div className="scope-toggle" aria-label="Automaton scope">
                <button
                  className={`scope-button${scope === "all" ? " is-active" : ""}`}
                  onClick={() => {
                    setScope("all");
                  }}
                  type="button"
                >
                  Global Scope
                </button>
                <button
                  className={`scope-button${scope === "mine" ? " is-active" : ""}`}
                  onClick={() => {
                    setScope("mine");
                  }}
                  type="button"
                >
                  My Automatons
                </button>
              </div>

              <dl className="status-grid">
                <div className="status-card">
                  <dt>Visible</dt>
                  <dd>{visibleAutomatons.length} organisms</dd>
                </div>
                <div className="status-card">
                  <dt>Writable CLI</dt>
                  <dd>
                    {
                      mockAutomatons.filter((entry) =>
                        isOwnedByViewer(entry.canisterId)
                      ).length
                    }{" "}
                    steward shells
                  </dd>
                </div>
                <div className="status-card">
                  <dt>Realtime</dt>
                  <dd>Mock event motion only</dd>
                </div>
              </dl>
            </div>
          </div>

          <AutomatonCanvas
            automatons={visibleAutomatons}
            onSelect={(canisterId) => {
              setSelectedCanisterId(canisterId);
            }}
            selectedCanisterId={selectedCanisterId}
            viewerAddress={SIMULATED_VIEWER_ADDRESS}
          />
        </section>

        <section className="frame frame-panels">
          <article className="info-panel">
            <p className="section-label">Interaction contract</p>
            <ol className="sequence-list">
              <li>Hover a cluster to reveal its live tier and net worth tooltip.</li>
              <li>Owned automatons retain their labels even when the cursor moves away.</li>
              <li>Click any organism to open the detail drawer and inspect shell panels.</li>
            </ol>
          </article>

          <article className="info-panel">
            <p className="section-label">System notes</p>
            <ul className="notes-list">
              {systemNotes.map((note) => (
                <li key={note}>{note}</li>
              ))}
            </ul>
          </article>
        </section>
      </main>

      <AutomatonDrawer
        automaton={selectedAutomaton}
        isOpen={selectedAutomaton !== null}
        onClose={() => {
          setSelectedCanisterId(null);
        }}
        viewerAddress={SIMULATED_VIEWER_ADDRESS}
      />

import type { ChainSlug } from "./automaton.js";

export const CATALOG_ENTRY_STATUSES = [
  "available",
  "coming_soon"
] as const;

export type CatalogEntryStatus = (typeof CATALOG_ENTRY_STATUSES)[number];
export type StrategyRiskLevel = 1 | 2 | 3 | 4 | 5;

export interface StrategyCatalogStats {
  apy: number | null;
  tvl: number | null;
}

export interface StrategyCatalogEntry {
  id: string;
  name: string;
  description: string;
  category: string;
  chains: ChainSlug[];
  riskLevel: StrategyRiskLevel;
  stats: StrategyCatalogStats;
  status: CatalogEntryStatus;
}

export interface SkillCatalogEntry {
  id: string;
  name: string;
  description: string;
  dependencies: string[];
  category: string;
  status: CatalogEntryStatus;
}

export interface CatalogResponse<TEntry> {
  items: TEntry[];
  updatedAt: number;
}

export type StrategyCatalogResponse = CatalogResponse<StrategyCatalogEntry>;
export type SkillCatalogResponse = CatalogResponse<SkillCatalogEntry>;

