.cli-prompt,
.cli-prompt-label {
  color: var(--color-tier-normal, #7a7);
}

.cli-input-row {
  display: grid;
  grid-template-columns: auto 1fr auto;
  margin-top: 0.7rem;
}

.cli-prompt-label {
  display: grid;
  place-items: center;
  padding: 0 0.8rem;
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-right: 0;
  background: rgba(34, 34, 34, 0.8);
}

.cli-input {
  min-width: 0;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(12, 12, 12, 0.88);
  color: var(--color-drawer-text, #cccccc);
  padding: 0.75rem 0.8rem;
  outline: none;
}

.cli-input::placeholder {
  color: var(--color-drawer-subtle, #555555);
}

.cli-send {
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-left: 0;
  background: rgba(58, 58, 58, 0.9);
  color: var(--color-drawer-text, #cccccc);
  padding: 0 1rem;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  cursor: pointer;
}

.cli-send:hover {
  background: rgba(96, 96, 96, 0.96);
}

@media (max-width: 1080px) {
  .stage-toolbar,
  .frame-panels,
  .status-grid,
  .drawer-grid,
  .drawer-bottom {
    grid-template-columns: 1fr;
  }

  .info-panel + .info-panel {
    border-left: 0;
    border-top: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.18);
  }
}

@media (max-width: 720px) {
  .app-shell {
    padding: var(--space-sm, 1rem);
  }

  .site-header {
    grid-template-columns: 1fr auto;
    align-items: start;
  }

  .menu-toggle {
    display: inline-flex;
  }

  .header-actions {
    display: none;
    grid-column: 1 / -1;
    width: 100%;
    margin: 0;
    padding-top: var(--space-sm, 1rem);
    border-top: var(--border-hairline, 1px) solid rgba(33, 29, 26, 0.18);
  }

  .header-actions.is-open {
    display: grid;
    gap: var(--space-sm, 1rem);
  }

  .nav-cluster,
  .header-utility,
  .scope-toggle {
    display: grid;
    width: 100%;
  }

  .nav-button,
  .scope-button {
    width: 100%;
    border-right: var(--border-hairline, 1px) solid var(--color-line, #211d1a);
    text-align: left;
  }

  .nav-button + .nav-button,
  .scope-button + .scope-button {
    border-top: 0;
  }

  .wallet-button,
  .canvas-wrap {
    width: 100%;
  }

  .frame-stage,
  .info-panel {
    padding: var(--space-md, 1.5rem);
  }

  h2 {
    max-width: none;
    font-size: clamp(2.4rem, 12vw, 3.8rem);
  }

  .canvas-wrap {
    min-height: 24rem;
  }

  .automaton-drawer {
    max-height: 100vh;
  }

  .drawer-inner {
    padding: 1.3rem 1.1rem 1.2rem;
  }

  .drawer-top {
    flex-wrap: wrap;
    padding-right: 4rem;
  }

  .panel-heading {
    align-items: start;
    flex-direction: column;
  }
}

